INSERT INTO public.call_analytics VALUES (31, '7b31dce6-0ed1-4c99-9c65-c449dd7278cb', '8335027643', 'IN', 'ANSWER', '2026-03-17 19:04:40', '2026-03-17 19:04:58', 19, 60, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/93aa8649-e83b-473d-9956-80c7e11c826c.mp3', 'The user called to inquire about their subscription plan. The agent confirmed that the user''s monthly plan is valid until March 20, 2026. The user had previously submitted a renewal request, which was pending. The call ended abruptly before any further actions or a final outcome could be determined.', 'neutral', '2026-03-17 13:34:40.900591', 1.15845176);
INSERT INTO public.call_analytics VALUES (32, '47391a69-e145-4695-ba0f-fcaed740ae3c', '7980810115', 'IN', 'ANSWER', '2026-03-17 22:07:55', '2026-03-17 22:09:30', 95, 120, 'Normal Hangup', 'API Request', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/39dd85bf-daf9-4aeb-a4de-83cd253a5a4c.mp3', 'The user, Vishesh Singh, called to inquire about newspaper subscription plans and expressed interest in a yearly plan. He provided his name, contact number (7980810115), and address (Barrackpore, Kolkata). I checked the system and informed him that a subscription request already exists for this contact number with a pending status. He acknowledged this and said he had no further questions. The call ended after I provided the closing greetings.', 'neutral', '2026-03-17 16:37:55.851972', 8.51511945);
INSERT INTO public.call_analytics VALUES (33, '579b197b-a438-4966-8f84-d98cbea84e66', '7980810115', 'IN', 'ANSWER', '2026-03-17 22:15:16', '2026-03-17 22:17:15', 119, 120, 'Normal Hangup', 'API Request', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/4947e359-34ed-48f2-9e80-978c0a884243.mp3', 'The user, Vishesh Singh, called to inquire about a new subscription. He decided on the Yearly plan. I confirmed his details (Name: Vishesh Singh, Contact: 7980810114, Address: 18/2 Ghola, Sodpur) and processed the subscription request for the Yearly plan starting from 2026-03-18. The request was noted successfully.', 'neutral', '2026-03-17 16:47:20.199258', 11.87727248);
INSERT INTO public.call_analytics VALUES (34, '5c3822d1-a15d-4fd2-9073-dfb3d0cde862', '7980810115', 'IN', 'ANSWER', '2026-03-17 22:17:26', '2026-03-17 22:19:05', 100, 120, 'Normal Hangup', 'API Request', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/1c7d333e-3ea9-4f94-a4cb-4cd53fd442fb.mp3', 'The user called asking for information about the newspaper. I provided details about Ei Samay''s features and commitment to neutral reporting. The user then specifically asked about an online version. I informed them that currently we only offer print subscriptions but could transfer them to a representative for online queries. The user declined the transfer and decided to call back later. The call ended politely.', 'neutral', '2026-03-17 16:47:26.346756', 6.56147964);
INSERT INTO public.call_analytics VALUES (35, 'ce12acc3-cf3e-4635-adb9-9e869b286527', '7980810115', 'IN', 'ANSWER', '2026-03-17 23:40:32', '2026-03-17 23:41:48', 77, 120, 'Normal Hangup', 'API Request', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/df5cf036-82d8-4e63-8089-00b8cbe18cc5.mp3', 'The user, Vishesh Singh, an existing subscriber (though currently inactive) called to inquire about the features of the Ei Samay newspaper. He asked if Ei Samay has an English newspaper (no), and if they deliver outside of West Bengal (no). He did not request any specific action like renewal during this call. The call ended after I provided this information.', 'neutral', '2026-03-17 18:10:24.817531', 3.851417775);
INSERT INTO public.call_analytics VALUES (36, 'b8366d69-4aea-406b-bc92-bfaacf7d1941', '7980810115', 'IN', 'ANSWER', '2026-03-18 13:48:47', '2026-03-18 13:49:59', 73, 120, 'Normal Hangup', 'API Request', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/d6fdf179-9d47-4e6b-b47e-084010c90d55.mp3', 'The user called to confirm his registered phone number, which was provided as 7980810115. I confirmed the number and informed him he is an existing subscriber with a deactivated Half Yearly plan. He then asked if an online version of the newspaper was available, to which I replied that only the print edition is offered. He also inquired about the pricing plans, and I provided the details for Monthly (₹200), Quarterly (₹500), Half Yearly (₹900), and Yearly (₹1650) plans. The user stated he would call back later. The call ended after providing the standard closing message.', 'neutral', '2026-03-18 08:18:47.665647', 4.7536166049999995);
INSERT INTO public.call_analytics VALUES (37, '0b23e798-0d64-4c3f-8bba-2431a15ac0ac', '8584022211', 'IN', 'ANSWER', '2026-03-18 14:53:02', '2026-03-18 14:55:28', 147, 180, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/a3c44380-8b5b-40f6-b01e-b31f288ddbc1.mp3', 'The user called to inquire about the "Ei Samay" newspaper and its subscription details. The agent explained the newspaper''s features and then outlined the available subscription plans. The user attempted to provide their name and contact number, but the agent had difficulty understanding them due to unclear speech. After multiple attempts, the agent confirmed the user''s name as "Bidita" and received a contact number. However, the system indicated that this phone number was not registered, leading the agent to repeatedly ask if the user wanted to subscribe and to reconfirm their name and address. The call ended abruptly before a subscription could be finalized or further information could be gathered.', 'negative', '2026-03-18 09:23:02.585617', 13.999652950000002);
INSERT INTO public.call_analytics VALUES (12, 'eed08d5a-b795-42e5-94a2-07c3fcac038a', '7980810115', 'IN', 'ANSWER', '2026-03-17 14:19:04', '2026-03-17 14:20:29', 86, 120, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/a239683a-289d-47a5-8b5e-25b9d6275e6d.mp3', 'The user called to inquire about pricing in Hindi. The agent provided pricing for monthly, quarterly, half-yearly, and yearly plans. The user then mentioned a price of "490 plus nMewtwoun po''" which the agent did not understand and asked to check for discounts. The user declined this. The call ended abruptly with the user. No actions were taken, and the user did not proceed with any purchase.', 'neutral', '2026-03-17 08:49:04.734511', 3.2106666666666666);
