INSERT INTO public.call_analytics VALUES (105, 'beaf1655-0c6a-4383-acd6-6be610298a92', '7509916839', 'IN', 'ANSWER', '2026-03-26 12:09:24', '2026-03-26 12:10:04', 40, 60, 'Normal Hangup', 'Caller', true, NULL, '9674511317', 0, '2026-03-26 12:10:04', 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/dcc49f3a-04aa-4848-beb8-a176cc1c15f5.mp3', 'The user called regarding a taxi. The agent, Priya, confirmed the user''s phone number. The user then asked to confirm the agent''s name, which Priya did. As the user''s input was deemed invalid for further processing, the agent transferred the call to another representative.', 'neutral', '2026-03-26 06:40:07.892812', 1.643096005);
INSERT INTO public.call_analytics VALUES (106, '35c3954d-6a89-4a90-aadd-cd8a470e0c61', '7509916839', 'IN', 'ANSWER', '2026-03-26 12:12:16', '2026-03-26 12:19:03', 408, 420, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/9af45295-4547-4a40-a06a-791f7954b4d0.mp3', 'The user initiated the call but was unable to provide a valid 10-digit phone number despite multiple attempts and suggestions. The call ended without a resolution or subscription request.', 'negative', '2026-03-26 06:44:17.545111', 56.491064689999995);
INSERT INTO public.call_analytics VALUES (107, 'f123153e-6e85-4950-b158-ccc230cb24aa', '7509916839', 'IN', 'ANSWER', '2026-03-26 12:19:16', '2026-03-26 12:21:08', 112, 120, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/b9948453-6fd6-4c29-9003-a5a90815aeea.mp3', 'The user called about a subscription offer from "Ei Samay" newspaper. The agent attempted to get the user''s PIN code, which the user eventually provided as "000000". The agent then explained the subscription offer, which includes up to 27% off for a yearly subscription, with options for monthly, quarterly, semi-annual, or yearly plans. The user inquired about an existing subscription request and asked about the "substitution" for "1 beat," which the agent interpreted as asking about the start date of the subscription. The call ended abruptly before a resolution could be reached.', 'neutral', '2026-03-26 06:49:44.677859', 7.632280515);
INSERT INTO public.call_analytics VALUES (108, '2d60f3d3-6bc3-4480-98d3-d0c0d0bf2c63', '7509916839', 'IN', 'ANSWER', '2026-03-26 12:22:11', '2026-03-26 12:23:56', 106, 120, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/269e8214-bb2b-4c6b-aa2d-d68df67ad0f4.mp3', 'The user called to subscribe to a newspaper for 3 months at ₹499. The agent clarified that only monthly, quarterly, half-yearly, and yearly plans are available. The user then mentioned "MBA first year," to which the agent responded with the yearly plan cost of ₹1650 and asked for the user''s PIN code. After the user provided a PIN, the agent confirmed it and proceeded to create a subscription request. However, the system indicated an existing subscription request on the user''s number, leading to confusion. The user then made several unclear statements ("App x," "karaoke song," "Amaregi varshik roop se sabse badi," "ANAGEN x6Y," "aaya tha"). The agent repeatedly checked the system, which sometimes showed no existing subscriber and at other times showed an existing request, suggesting a renewal. The call ended abruptly with the agent stating the system showed an existing subscription request for renewal, but the user details indicate an invalid contact number format was provided.', 'negative', '2026-03-26 06:53:06.149357', 7.652241075);
INSERT INTO public.call_analytics VALUES (109, 'e8867985-e094-4e37-9fd4-17a2543cf2b5', '7509916839', 'IN', 'ANSWER', '2026-03-26 12:33:16', '2026-03-26 12:35:05', 109, 120, 'Normal Hangup', 'API Request', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/19eef591-2338-400c-ad32-a5fd7f4c5809.mp3', 'The user, whose name is Bhola, called to inquire about newspaper subscription offers. I provided details about the available plans (Monthly, Quarterly, Half-Yearly, Yearly) with up to 27% discount. When I asked for his PIN code to proceed with a potential subscription request, the user declined to provide it. The user did not wish to proceed further with the subscription process at this time, so the call was ended.', 'neutral', '2026-03-26 07:05:09.67694', 6.765520919999999);
INSERT INTO public.call_analytics VALUES (110, '7b94efe8-fb2f-48cc-bfd3-13fdeee9bced', '7509916839', 'IN', 'ANSWER', '2026-03-26 14:49:40', '2026-03-26 14:49:52', 12, 60, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/10f3fb9b-9e52-4f4f-8620-7f1d000df7f5.mp3', 'The user called about an invalid contact number format. The agent explained that the provided number was not a valid 10-digit phone number. No actions were taken, and the call ended abruptly with the user.', 'neutral', '2026-03-26 09:19:55.972361', 0.322557105);
INSERT INTO public.call_analytics VALUES (111, 'd6f2640e-f09e-4773-99e4-dc17b9786639', '7980810115', 'IN', 'ANSWER', '2026-03-26 18:20:28', '2026-03-26 18:21:26', 58, 60, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/f81e78ce-dc5b-494d-a999-ec11fe8f55f3.mp3', 'The user called to inquire about subscription plans for a newspaper. The agent outlined monthly, quarterly, half-yearly, and yearly plans. The user then asked about delivery areas and was asked for their pin code. The call ended abruptly before the pin code was fully provided or a specific delivery area was confirmed.', 'neutral', '2026-03-26 12:51:30.183616', 2.5677504649999996);
INSERT INTO public.call_analytics VALUES (112, 'a0f0ae21-b411-4e44-a603-c0faef9f06d2', '7509916839', 'IN', 'ANSWER', '2026-03-27 11:06:58', '2026-03-27 11:09:09', 131, 180, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/8a0fd776-0dd4-4b8c-9390-5fa63cb1b4cc.mp3', 'The user called about "Adam''s tech consulting" but the agent, from "Ei Shomoy Shongbadpotro" (This Time Newspaper), initially misunderstood and thought the user wanted information about the newspaper. The conversation involved a significant amount of confusion regarding the user''s language preference, with the user switching between Bengali, English, and other languages, and the agent repeatedly asking for clarification. The agent also attempted to collect the user''s PIN code for location services, which also led to miscommunication. Ultimately, the user clarified they wanted to speak in English. The agent apologized for the previous misunderstanding and asked how they could help. The user then asked a question about a "3.7 automatic" and "90 ka tha.4", which the agent did not fully understand before the call ended. No specific actions were taken beyond attempted information gathering and clarification, and the call ended without resolving the user''s initial query or their final question.', 'negative', '2026-03-27 05:39:15.258605', 13.354030485000001);
INSERT INTO public.call_analytics VALUES (113, 'ce534cdd-075d-4d4c-a961-f15a412f7f9d', '7509916839', 'IN', 'ANSWER', '2026-03-27 11:13:00', '2026-03-27 11:14:57', 118, 120, 'Normal Hangup', 'API Request', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/1eececf4-8b2a-47b6-8b2b-78e57a49e09d.mp3', 'The user called to inquire about newspaper subscription plans. They specifically asked for a one-day plan, which is not available. I informed them about the shortest available plan (monthly) and other options (quarterly, half-yearly, yearly), but the user stated they did not want those. The call ended after I confirmed their lack of interest in the available plans.', 'negative', '2026-03-27 05:45:02.915638', 9.03224581);
INSERT INTO public.call_analytics VALUES (114, '38061eed-7aea-45f6-bfc5-e8f10751a7e7', '9980070984', 'IN', 'ANSWER', '2026-03-27 15:27:39', '2026-03-27 15:28:36', 57, 60, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/4c0bb690-88fe-45b7-ad4e-a14fa48d4dbf.mp3', 'The user called inquiring about coffee, which the agent misunderstood as a query about newspaper stock. The agent then asked for the user''s PIN code to check local availability. The user provided seemingly random input and then expressed interest in "top news." The agent clarified that they didn''t understand the user''s intent and asked if the newspaper was out of stock. After a brief system check, the agent informed the user that no subscription request was found for their number and asked if they wanted to subscribe anew. The user''s input was consistently invalid, leading to an invalid contact number format error in the system. The call ended with the user''s input being unclear.', 'negative', '2026-03-27 09:58:27.342147', 4.61282997);
INSERT INTO public.call_analytics VALUES (115, '3cb9c0cd-f519-4325-86ae-da5fd8ff6867', '8335027643', 'IN', 'ANSWER', '2026-04-03 15:26:48', '2026-04-03 15:27:26', 39, 60, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/a48ba888-609e-4155-8b71-d895ffe132e0.mp3', 'The user received a call from Priya at "Ei Shomoy newspaper" about a special subscription offer. The agent described the newspaper''s features like fearless and unbiased reporting, in-depth news, modern layout, and easy navigation. The user initially responded with "Hello" which the agent confirmed. The agent then explained that subscriptions can be taken from home and listed the available plans: monthly, quarterly, half-yearly, and yearly. The user''s contact number was flagged as invalid. The call ended abruptly by the user.', 'neutral', '2026-04-03 09:57:31.785811', 3.26863411);
INSERT INTO public.call_analytics VALUES (116, 'd1ae611e-6de3-40d4-81f2-35d0350ad22b', '8335027643', 'IN', 'ANSWER', '2026-04-03 15:27:29', '2026-04-03 15:27:56', 28, 60, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/be37e3f8-be48-4353-bd8f-43865b68972a.mp3', 'The user called about a special subscription offer for "Ei Samay" newspaper, which provides unbiased news with a modern layout and easy navigation. The agent explained the subscription options, including discounts of up to 27% for yearly subscriptions, and offered flexibility with three, six, or twelve-month plans. The agent then asked for the user''s area pin code to proceed. The call was ended abruptly by the user before the pin code could be provided or any actions taken. The outcome was that the user did not complete the subscription process.', 'neutral', '2026-04-03 09:58:01.729849', 1.7880872949999997);
INSERT INTO public.call_analytics VALUES (117, '8e3b6963-c578-4f16-8e69-a4c31d24efb3', '8335027643', 'IN', 'ANSWER', '2026-04-03 16:05:10', '2026-04-03 16:05:28', 18, 60, 'Normal Hangup', 'Caller', false, NULL, NULL, NULL, NULL, 'https://aps1.media.plivo.com/v1/Account/MAMDLHY2M4NDJKYTRHNJ/Recording/f334083a-3d23-4faf-ba15-4e9402f91c47.mp3', 'The user called about an invalid contact number format. They did not provide any further details or take any actions. The call ended abruptly with the user.', 'neutral', '2026-04-03 10:35:34.472112', 0);
